void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("pirate2_1");			link.l1 = "...";			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}